'use client';

/**
 * Hook for managing follow-ups
 */

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useUserProfile } from '@/hooks/useUserProfile';
import { useSecretaryDoctors } from '@/hooks/useSecretaryDoctors';

export const FOLLOW_UPS_KEY = 'follow-ups';

interface FollowUp {
    id: string;
    user_id: string;
    deal_id: string;
    scheduled_date: string;
    scheduled_time?: string;
    description?: string;
    status: 'pendente' | 'concluido' | 'cancelado';
    completed_notes?: string;
    completed_at?: string;
    created_at: string;
    deal?: {
        id: string;
        title: string;
        contact?: {
            id: string;
            full_name?: string;
            phone?: string;
        };
    };
}

interface CreateFollowUpData {
    deal_id: string;
    scheduled_date: string;
    scheduled_time?: string;
    description?: string;
}

interface UpdateFollowUpData {
    scheduled_date?: string;
    scheduled_time?: string;
    description?: string;
    status?: 'pendente' | 'concluido' | 'cancelado';
    completed_notes?: string;
}

export function useFollowUps() {
    const { user } = useAuth();
    const { profile, isSecretaria } = useUserProfile();
    const { doctorIds, isLoading: isLoadingDoctors } = useSecretaryDoctors();
    const queryClient = useQueryClient();

    const userIds = user?.id
        ? isSecretaria && doctorIds?.length
            ? [...doctorIds, user.id]
            : [user.id]
        : [];

    const isAdmin = profile?.role === 'admin' || profile?.role === 'dono';

    const { data: followUps = [], isLoading, error } = useQuery({
        queryKey: [FOLLOW_UPS_KEY, userIds],
        queryFn: async (): Promise<FollowUp[]> => {
            if (!user?.id) return [];

            const supabase = createClient();

            let query = supabase
                .from('crm_follow_ups' as any)
                .select(`
                    *,
                    deal:crm_deals(id, title, contact:crm_contacts(id, full_name, phone))
                `)
                .order('scheduled_date', { ascending: true });

            if (!isAdmin && userIds.length > 0) {
                query = query.in('user_id', userIds);
            }

            const { data, error } = await query;

            if (error) {
                console.error('[useFollowUps] Fetch error:', error);
                throw error;
            }

            return (data || []) as FollowUp[];
        },
        enabled: !!user?.id && (!isSecretaria || !isLoadingDoctors),
        staleTime: 2 * 60 * 1000,
    });

    const createFollowUp = useMutation({
        mutationFn: async (data: CreateFollowUpData) => {
            if (!user?.id) throw new Error('User not authenticated');

            const supabase = createClient();

            const { data: followUp, error } = await supabase
                .from('crm_follow_ups' as any)
                .insert({
                    ...data,
                    user_id: user.id,
                    status: 'pendente',
                } as never)
                .select()
                .single();

            if (error) throw error;
            return followUp;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [FOLLOW_UPS_KEY] });
        },
    });

    const updateFollowUp = useMutation({
        mutationFn: async ({ id, data }: { id: string; data: UpdateFollowUpData }) => {
            const supabase = createClient();

            const updateData: any = { ...data };

            // If completing, add timestamp
            if (data.status === 'concluido') {
                updateData.completed_at = new Date().toISOString();
            }

            const { data: followUp, error } = await supabase
                .from('crm_follow_ups' as any)
                .update(updateData as never)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return followUp;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [FOLLOW_UPS_KEY] });
        },
    });

    const deleteFollowUp = useMutation({
        mutationFn: async (id: string) => {
            const supabase = createClient();

            const { error } = await supabase
                .from('crm_follow_ups' as any)
                .delete()
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [FOLLOW_UPS_KEY] });
        },
    });

    return {
        followUps,
        isLoading,
        error,
        createFollowUp: createFollowUp.mutateAsync,
        updateFollowUp: updateFollowUp.mutateAsync,
        deleteFollowUp: deleteFollowUp.mutateAsync,
        isCreating: createFollowUp.isPending,
        isUpdating: updateFollowUp.isPending,
        isDeleting: deleteFollowUp.isPending,
    };
}
